import React,{useEffect} from 'react'
import Template from './Template'

const Signup = () => {
  const navigate=useNavigate();

  useEffect(() => {
    if(window.localStorage.getItem('isLoggedIn'))
      navigate('/');
  }, []);

  return (
    <div>
        <Template
            formtype="signup"
        />
    </div>
  )
}

export default Signup
